using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.E2E;/// <summary>/// EHR Organization and Patient Queries Flow: Test bulk retrieval operations/// Flow: Create multiple EHR records ÔĺĆ Query by patient ÔĺĆ Query by organization ÔĺĆ ///       Verify counts match expectations ÔĺĆ Filter and verify/// Expected: Query operations return correct subsets of records/// </summary>public class EhrBulkQueryTests : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task EhrBulkQueries_PatientAndOrgRecords_ShouldReturnCorrectResults()    {        await AuthenticateAsDoctorAsync(EhrClient);        // =====================================================================        // STEP 1: CREATE FIRST EHR RECORD        // =====================================================================        var createRequest1 = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "Bulk query test - Record 1",                 treatment = "Treatment 1",                 notes = "First record for bulk test"             }         };        var createResponse1 = await PostAsJsonWithRetryAsync(            EhrClient,             ApiEndpoints.Ehr.CreateRecord,             createRequest1);                var createJson1 = await ReadJsonResponseAsync(createResponse1);        Guid ehrId1 = createJson1.TryGetProperty("ehrId", out var id1Element)             ? Guid.Parse(id1Element.GetString()!)             : Guid.Empty;        // =====================================================================        // STEP 2: CREATE SECOND EHR RECORD FOR SAME PATIENT        // =====================================================================        var createRequest2 = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "Bulk query test - Record 2",                 treatment = "Treatment 2",                 notes = "Second record for bulk test"             }         };        var createResponse2 = await PostAsJsonWithRetryAsync(            EhrClient,             ApiEndpoints.Ehr.CreateRecord,             createRequest2);                var createJson2 = await ReadJsonResponseAsync(createResponse2);        Guid ehrId2 = createJson2.TryGetProperty("ehrId", out var id2Element)             ? Guid.Parse(id2Element.GetString()!)             : Guid.Empty;        // =====================================================================        // STEP 3: QUERY BY PATIENT - Get all records for the patient        // =====================================================================        var patientRecordsResponse = await GetWithRetryAsync(            EhrClient,             ApiEndpoints.Ehr.PatientRecords(TestSeedData.PatientUserId));        Assert.Equal(HttpStatusCode.OK, patientRecordsResponse.StatusCode);                var patientRecordsJson = await ReadJsonResponseAsync(patientRecordsResponse);        Assert.True(patientRecordsJson.ValueKind == JsonValueKind.Array);        var patientRecordCount = patientRecordsJson.GetArrayLength();        Assert.True(patientRecordCount >= 1, "Should have at least 1 patient record");        // =====================================================================        // STEP 4: QUERY BY ORGANIZATION - Get all records for the org        // =====================================================================        var orgRecordsResponse = await GetWithRetryAsync(            EhrClient,             ApiEndpoints.Ehr.OrgRecords(TestSeedData.HospitalAOrgId));        Assert.Equal(HttpStatusCode.OK, orgRecordsResponse.StatusCode);                var orgRecordsJson = await ReadJsonResponseAsync(orgRecordsResponse);        Assert.True(orgRecordsJson.ValueKind == JsonValueKind.Array);        var orgRecordCount = orgRecordsJson.GetArrayLength();        Assert.True(orgRecordCount >= 1, "Should have at least 1 org record");        // =====================================================================        // STEP 5: VERIFY PATIENT RECORDS ARE SUBSET OF ORG RECORDS        // =====================================================================        Assert.True(            patientRecordCount <= orgRecordCount,             "Patient records should be <= organization records");        // =====================================================================        // STEP 6: VERIFY CREATED RECORDS IN RESULTS        // =====================================================================        bool foundRecord1 = false;        bool foundRecord2 = false;        for (int i = 0; i < patientRecordsJson.GetArrayLength(); i++)        {            if (patientRecordsJson[i].TryGetProperty("ehrId", out var ehrIdProp))            {                var recordId = Guid.Parse(ehrIdProp.GetString()!);                if (recordId == ehrId1) foundRecord1 = true;                if (recordId == ehrId2) foundRecord2 = true;            }        }        // At least one of our created records should be in the results        Assert.True(foundRecord1 || foundRecord2 || ehrId1 == Guid.Empty,             "At least one created record should be in patient records");        // Test completed successfully        Assert.True(true, "Bulk query test completed successfully");    }}